#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
int t,a0,a1,b0,b1;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--)
	{
		cin>>a0>>a1>>b0>>b1;
		int t=a0/a1,t2=b1/b0,ans=0;
		for(int i=1;i<=b1/i;i++)
		{
			if(b1%i==0)
			{
				if(i%a1==0&&(__gcd(t,i/a1)==1)&&(__gcd(t2,b1/i)==1)) ans++;
				int nxt=b1/i;
				if(nxt==i) continue;
				if(nxt%a1==0&&(__gcd(t,nxt/a1)==1)&&(__gcd(t2,b1/nxt)==1)) ans++;
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
